// escapeHTML escapes special HTML characters to prevent XSS and ensure proper formatting
func escapeHTML(text string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(text)
}

// SendFeedbackEmail sends the generated feedback email using SMTP
func SendFeedbackEmail(smtpHost string, smtpPort int, username, password string, emailBody string) error {
	// Extract "From" and "To" addresses from email body
	lines := strings.Split(emailBody, "\r\n")
	var fromAddr, toAddr string

	for _, line := range lines {
		if strings.HasPrefix(line, "From: ") {
			fromAddr = strings.TrimPrefix(line, "From: ")
		}
		if strings.HasPrefix(line, "To: ") {
			toAddr = strings.TrimPrefix(line, "To: ")
		}
	}

	if fromAddr == "" || toAddr == "" {
		return fmt.Errorf("could not extract From or To addresses from email body")
	}

	// SMTP authentication
	auth := smtp.PlainAuth("", username, password, smtpHost)

	// Send email
	err := smtp.SendMail(
		fmt.Sprintf("%s:%d", smtpHost, smtpPort),
		auth,
		fromAddr,
		[]string{toAddr},
		[]byte(emailBody),
	)

	return err
}

