// htmlEscape escapes special HTML characters to prevent XSS attacks
func htmlEscape(text string) string {
	text = strings.ReplaceAll(text, "&", "&amp;")
	text = strings.ReplaceAll(text, "<", "&lt;")
	text = strings.ReplaceAll(text, ">", "&gt;")
	text = strings.ReplaceAll(text, "\"", "&quot;")
	text = strings.ReplaceAll(text, "'", "&#39;")
	text = strings.ReplaceAll(text, "\n", "<br>")
	return text
}

// SendEmail sends the generated email using SMTP
func SendEmail(smtpHost string, smtpPort int, username string, password string, fromAddr string, toAddr string, emailBody string) error {
	// SMTP server address
	addr := fmt.Sprintf("%s:%d", smtpHost, smtpPort)

	// SMTP authentication
	auth := smtp.PlainAuth("", username, password, smtpHost)

	// Split the email body to extract headers and content
	lines := strings.Split(emailBody, "\r\n")

	// Find the blank line that separates headers from body
	bodyStart := 0
	for i, line := range lines {
		if line == "" {
			bodyStart = i + 1
			break
		}
	}

	// Reconstruct headers and body
	headers := strings.Join(lines[:bodyStart-1], "\r\n")
	body := strings.Join(lines[bodyStart:], "\r\n")

	// Send the email
	return smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(headers+"\r\n\r\n"+body))
}

