package main

import (
	"fmt"
	"net/mail"
	"strings"
	"mime/quotedprintable"
	"bytes"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Encode subject for proper handling of special characters
	encodedSubject := encodeSubject(subject)

	// Construct email headers with proper MIME encoding
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\n"+
		"MIME-Version: 1.0\r\n"+
		"Content-Type: text/html; charset=UTF-8\r\n"+
		"Content-Transfer-Encoding: quoted-printable\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Construct HTML body with proper escaping
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		userName,
		subject,
		feedbackContent,
	)

	// Encode the HTML body using quoted-printable
	encodedBody, err := encodeQuotedPrintable(htmlBody)
	if err != nil {
		return "", fmt.Errorf("failed to encode email body: %w", err)
	}

	// Combine headers and encoded body
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

// htmlEscape escapes HTML special characters to prevent XSS attacks
func htmlEscape(s string) string {
	return strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	).Replace(s)
}

// encodeSubject encodes email subject with proper MIME encoding
func encodeSubject(subject string) string {
	// If subject contains non-ASCII or special characters, encode it
	if needsEncoding(subject) {
		return fmt.Sprintf("=?UTF-8?Q?%s?=", encodeQuotedPrintableString(subject))
	}
	return subject
}

// needsEncoding checks if string contains characters that need encoding
func needsEncoding(s string) bool {
	for _, r := range s {
		if r > 127 || r == '\r' || r == '\n' {
			return true
		}
	}
	return false
}

// encodeQuotedPrintableString encodes a string using quoted-printable
func encodeQuotedPrintableString(s string) string {
	var buf bytes.Buffer
	w := quotedprintable.NewWriter(&buf)
	w.Write([]byte(s))
	w.Close()
	return strings.ReplaceAll(buf.String(), "\n", "")
}

// encodeQuotedPrintable encodes the entire HTML body using quoted-printable
func encodeQuotedPrintable(body string) (string, error) {
	var buf bytes.Buffer
	w := quotedprintable.NewWriter(&buf)

	_, err := w.Write([]byte(body))
	if err != nil {
		return "", err
	}

	err = w.Close()
	if err != nil {
		return "", err
	}

	return buf.String(), nil
}

