	sanitizedSubject := html.EscapeString(subject)
	sanitizedFeedbackContent := html.EscapeString(feedbackContent)

	// Escape special characters in email headers to prevent header injection
	escapedFromAddr := strings.ReplaceAll(fromAddr, "\r", "")
	escapedFromAddr = strings.ReplaceAll(escapedFromAddr, "\n", "")
	escapedToAddr := strings.ReplaceAll(toAddr, "\r", "")
	escapedToAddr = strings.ReplaceAll(escapedToAddr, "\n", "")

	// Construct email headers with proper escaping
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Escape subject line for email headers
	escapedSubject := strings.ReplaceAll(emailSubject, "\r", "")
	escapedSubject = strings.ReplaceAll(escapedSubject, "\n", "")

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
