package main

import (
	"fmt"
	"net/mail"
	"net/smtp"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Validate required fields
	if userName == "" {
		return "", fmt.Errorf("userName must not be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject must not be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedbackContent must not be empty")
	}

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Escape HTML special characters to prevent XSS and ensure proper display
	escapedUserName := htmlEscape(userName)
	escapedSubject := htmlEscape(subject)
	escapedFeedback := htmlEscape(feedbackContent)

	// Construct proper email headers with proper MIME formatting
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Construct HTML body with proper formatting
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 20px; }
    .feedback-container { max-width: 800px; margin: 0 auto; }
    .feedback-header { background-color: #f0f0f0; padding: 15px; border-radius: 5px; }
    .feedback-content { background-color: #f9f9f9; padding: 15px; border: 1px solid #ddd; border-radius: 5px; margin-top: 10px; }
    .field-label { font-weight: bold; color: #333; }
    .field-value { margin-bottom: 15px; }
  </style>
</head>
<body>
  <div class="feedback-container">
    <div class="feedback-header">
      <h2>User Feedback Received</h2>
    </div>
    <div class="feedback-content">
      <div class="field-value">
        <span class="field-label">Submitted by:</span> %s
      </div>
      <div class="field-value">
        <span class="field-label">Subject:</span> %s
      </div>
      <div class="field-value">
        <span class="field-label">Message:</span><br>
        <div style="white-space: pre-wrap; margin-top: 10px;">%s</div>
      </div>
    </div>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes HTML special characters to prevent XSS attacks
func htmlEscape(s string) string {
	escapeMap := map[rune]string{
		'<': "&lt;",
		'>': "&gt;",
		'&': "&amp;",
		'"': "&quot;",
		'\'': "&#39;",
	}

	var escaped []rune
	for _, r := range s {
		if replacement, ok := escapeMap[r]; ok {
			escaped = append(escaped, []rune(replacement)...)
		} else {
			escaped = append(escaped, r)
		}
	}
	return string(escaped)
}

// SendFeedbackEmail sends the feedback email using smtp.SendMail
// This is an additional helper function that demonstrates how to use BuildFeedbackEmail
func SendFeedbackEmail(smtpHost string, smtpPort string, smtpUsername string, smtpPassword string,
	fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {

	// Build the email body
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Set up authentication
	auth := smtp.PlainAuth("", smtpUsername, smtpPassword, smtpHost)

	// Connect to SMTP server
	addr := fmt.Sprintf("%s:%s", smtpHost, smtpPort)

	// Send the email
	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

// Example usage
func main() {
	// Example data
	fromAddr := "sender@example.com"
	toAddr := "support@example.com"
	userName := "John Doe"
	subject := "Bug Report"
	feedbackContent := "I found a bug in the login system. When I try to login with my credentials, I get an error message saying 'Invalid credentials' even though they are correct."

	// Build the email
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Email built successfully!")
	fmt.Println("Email length:", len(emailBody))

	// To send the email, you would use:
	// err = SendFeedbackEmail(
	//     "smtp.example.com",
