        }
        .content-box {
            background-color: #fff;
            border: 1px solid #ddd;
            border-radius: 5px;
            padding: 15px;
            margin-top: 10px;
        }
    </style>
</head>
<body>
    <div class="header">
        <h2 style="margin: 0; color: #007bff;">New User Feedback Received</h2>
        <p style="margin: 5px 0 0 0; color: #666;">Please review the following feedback submitted by a user.</p>
    </div>

    <div class="field">
        <span class="field-label">User Name:</span>
        <div class="field-value">%s</div>
    </div>

    <div class="field">
        <span class="field-label">Feedback Subject:</span>
        <div class="field-value">%s</div>
