	message.WriteString("\r\n")

	// Write HTML body
	message.WriteString(htmlBody)

	return message.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS
func escapeHTML(text string) string {
	text = strings.ReplaceAll(text, "&", "&amp;")
