import (
	"fmt"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape HTML special characters to prevent XSS
	escapedUserName := htmlEscape(userName)
	escapedSubject := htmlEscape(subject)
	escapedFeedback := htmlEscape(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", escapedSubject)

	// Properly format email headers with MIME encoding for subject
	encodedSubject := mimeEncode(emailSubject)
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 20px; }
    .feedback-container { background-color: #f9f9f9; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
    .field-label { font-weight: bold; color: #333; margin-top: 15px; }
    .field-value { margin: 5px 0 15px 0; }
    .message-content { 
      white-space: pre-wrap; 
      background-color: #fff; 
      padding: 15px; 
      border: 1px solid #ccc; 
      border-radius: 3px; 
      margin-top: 5px;
    }
  </style>
</head>
<body>
  <h2>User Feedback Received</h2>
  <div class="feedback-container">
    <div class="field-label">Submitted by:</div>
    <div class="field-value">%s</div>

    <div class="field-label">Subject:</div>
    <div class="field-value">%s</div>

    <div class="field-label">Message:</div>
    <div class="message-content">%s</div>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes HTML special characters to prevent XSS attacks
func htmlEscape(text string) string {
	text = strings.ReplaceAll(text, "&", "&amp;")
	text = strings.ReplaceAll(text, "<", "&lt;")
	text = strings.ReplaceAll(text, ">", "&gt;")
	text = strings.ReplaceAll(text, "\"", "&quot;")
	text = strings.ReplaceAll(text, "'", "&#39;")
	return text
}

// mimeEncode encodes non-ASCII characters in email subject
func mimeEncode(subject string) string {
	// Simple implementation - for production use proper MIME encoding
	// This handles basic cases where subject contains only ASCII
	if isASCII(subject) {
		return subject
	}
	// For non-ASCII, we should use proper encoding like quoted-printable
	// For simplicity, we'll just return as-is with warning
	// In production, use mime.QEncoding or similar
	return subject
}

// isASCII checks if a string contains only ASCII characters
func isASCII(s string) bool {
	for i := 0; i < len(s); i++ {
		if s[i] > 127 {
			return false
		}
	}
	return true
}

// SendFeedbackEmail sends the feedback email using net/smtp
func SendFeedbackEmail(smtpHost string, smtpPort string, smtpUsername string, smtpPassword string, 
	fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {

	// Build the email body
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Set up authentication
	auth := smtp.PlainAuth("", smtpUsername, smtpPassword, smtpHost)

	// Connect to SMTP server
	addr := fmt.Sprintf("%s:%s", smtpHost, smtpPort)

	// Send the email
	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

