package main

import (
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user input to prevent XSS attacks
	sanitizedUserName := html.EscapeString(userName)
	sanitizedSubject := html.EscapeString(subject)
	sanitizedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct email headers with proper encoding for subject
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Use MIME encoding for subject to handle special characters
	encodedSubject := mimeEncode(emailSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		encodedSubject,
	)

	// Construct HTML body with sanitized content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		sanitizedUserName,
		sanitizedSubject,
		sanitizedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// mimeEncode encodes a string for use in email headers using MIME encoding
func mimeEncode(text string) string {
	// Simple MIME encoding for ASCII subjects
	// For production use, consider using mime.QEncoding or mime.BEncoding from mime package
	if isASCII(text) {
		return text
	}

	// For non-ASCII, use quoted-printable encoding
	var result strings.Builder
	for _, r := range text {
		if r >= 32 && r <= 126 && r != '=' && r != '?' && r != '_' {
			result.WriteRune(r)
		} else {
			result.WriteString(fmt.Sprintf("=%02X", r))
		}
	}
	return result.String()
}

// isASCII checks if a string contains only ASCII characters
func isASCII(s string) bool {
	for i := 0; i < len(s); i++ {
		if s[i] > 127 {
			return false
		}
	}
	return true
}

// SendFeedbackEmail sends the feedback email using SMTP
func SendFeedbackEmail(smtpServer string, smtpPort int, username, password string, 
	fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {

	// Build the email message
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Set up authentication
	auth := smtp.PlainAuth("", username, password, smtpServer)

	// Connect to SMTP server
	addr := fmt.Sprintf("%s:%d", smtpServer, smtpPort)

	// Send the email
	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

