// BuildFeedbackEmail constructs an HTML email containing user feedback information
// Parameters:
//   - fromAddr: Sender's email address
//   - toAddr: Recipient's email address (customer support team)
//   - userName: Name of the user submitting feedback
//   - subject: Subject/title of the feedback
//   - feedbackContent: Detailed feedback content from the user
//
// Returns:
//   - emailBody: Complete email in RFC 5322 format ready for sending
//   - err: Error if any occurred during construction
func BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent string) (emailBody string, err error) {
	// Validate required parameters
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr are required")
	}
	if userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("userName, subject, and feedbackContent are required")
	}

	// Generate unique message ID
	messageID := fmt.Sprintf("<%d.%s@feedback.system>", time.Now().UnixNano(), strings.ReplaceAll(fromAddr, "@", "."))

	// Create HTML email body with proper formatting
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback: %s</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; }
        .header { background-color: #f8f9fa; padding: 15px; border-radius: 5px; margin-bottom: 20px; }
        .field { margin-bottom: 15px; }
        .label { font-weight: bold; color: #555; }
        .content { background-color: #f8f9fa; padding: 15px; border-radius: 5px; margin-top: 5px; }
        .timestamp { color: #666; font-size: 0.9em; margin-top: 20px; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>📝 New User Feedback Received</h2>
        </div>

        <div class="field">
            <div class="label">User Name:</div>
            <div class="content">%s</div>
        </div>

        <div class="field">
            <div class="label">Feedback Subject:</div>
            <div class="content">%s</div>
        </div>

        <div class="field">
            <div class="label">Feedback Content:</div>
            <div class="content">%s</div>
        </div>

        <div class="timestamp">
            Submitted on: %s
        </div>
    </div>
</body>
</html>`,
		escapeHTML(subject),
		escapeHTML(userName),
		escapeHTML(subject),
		escapeHTML(feedbackContent),
		time.Now().Format("2006-01-02 15:04:05 MST"))

	// Create plain text alternative for email clients that don't support HTML
	plainText := fmt.Sprintf(`User Feedback Report
====================

User Name: %s
Subject: %s
Feedback: %s

Submitted on: %s
`,
		userName,
		subject,
		feedbackContent,
		time.Now().Format("2006-01-02 15:04:05 MST"))

	// Generate email headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("User Feedback: %s", subject)
	headers["Message-ID"] = messageID
	headers["Date"] = time.Now().Format(time.RFC1123Z)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "multipart/alternative; boundary=\"feedback-boundary\""

	// Build the complete email body
	var bodyBuffer bytes.Buffer

	// Write headers
	for key, value := range headers {
		bodyBuffer.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	bodyBuffer.WriteString("\r\n")

	// Write multipart boundary for plain text
	bodyBuffer.WriteString("--feedback-boundary\r\n")
	bodyBuffer.WriteString("Content-Type: text/plain; charset=UTF-8\r\n")
	bodyBuffer.WriteString("Content-Transfer-Encoding: quoted-printable\r\n\r\n")
	bodyBuffer.WriteString(plainText)
	bodyBuffer.WriteString("\r\n")

	// Write multipart boundary for HTML
	bodyBuffer.WriteString("--feedback-boundary\r\n")
	bodyBuffer.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	bodyBuffer.WriteString("Content-Transfer-Encoding: quoted-printable\r\n\r\n")
	bodyBuffer.WriteString(htmlBody)
	bodyBuffer.WriteString("\r\n")

	// Write closing boundary
	bodyBuffer.WriteString("--feedback-boundary--\r\n")

	return bodyBuffer.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS attacks
func escapeHTML(text string) string {
	text = strings.ReplaceAll(text, "&", "&amp;")
	text = strings.ReplaceAll(text, "<", "&lt;")
	text = strings.ReplaceAll(text, ">", "&gt;")
	text = strings.ReplaceAll(text, "\"", "&quot;")
	text = strings.ReplaceAll(text, "'", "&#39;")
	return text
}

// SendFeedbackEmail sends the constructed feedback email using SMTP
// This is an additional helper function to demonstrate usage
func SendFeedbackEmail(smtpHost string, smtpPort int, username, password, fromAddr, toAddr, userName, subject, feedbackContent string) error {
	// Build the email
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
