// mimeEncode encodes a string for use in email headers (simplified version)
func mimeEncode(s string) string {
	// For production, consider using mime.QEncoding or mime.BEncoding
	// This is a simplified version that handles basic cases
	if strings.ContainsAny(s, "=?\"\r\n") {
