}

// qEncode performs quoted-printable-like encoding (simplified)
func qEncode(s string) string {
	var result strings.Builder
	for _, r := range s {
		if r >= 33 && r <= 126 && r != '=' && r != '?' && r != '_' {
			result.WriteRune(r)
		} else {
			result.WriteString(fmt.Sprintf("=%02X", r))
		}
	}
	return result.String()
}

