		Subject:         template.HTMLEscapeString(subject),
		FeedbackContent: template.HTMLEscapeString(feedbackContent),
	}

	// Parse and execute the template
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Construct the complete email with headers
	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = fmt.Sprintf("Feedback: %s", subject)
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=\"UTF-8\""

	var email strings.Builder
	for k, v := range headers {
		email.WriteString(fmt.Sprintf("%s: %s\r\n", k, v))
	}
	email.WriteString("\r\n")
	email.WriteString(buf.String())

