// SendFeedbackEmail sends the generated feedback email using SMTP
func SendFeedbackEmail(smtpHost string, smtpPort int, username, password, fromAddr, toAddr, userName, subject, feedbackContent string) error {
	// Build the email body
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// SMTP server address
	addr := fmt.Sprintf("%s:%d", smtpHost, smtpPort)

	// Authenticate with the SMTP server
	auth := smtp.PlainAuth("", username, password, smtpHost)

	// For TLS support (recommended for production)
	tlsConfig := &tls.Config{
		ServerName: smtpHost,
	}

	// Connect to the SMTP server
	client, err := smtp.Dial(addr)
	if err != nil {
		return fmt.Errorf("failed to connect to SMTP server: %w", err)
	}
	defer client.Close()

	// Start TLS if supported
	if err = client.StartTLS(tlsConfig); err != nil {
		return fmt.Errorf("failed to start TLS: %w", err)
	}

	// Authenticate
	if err = client.Auth(auth); err != nil {
		return fmt.Errorf("failed to authenticate: %w", err)
	}

	// Set the sender and recipient
	if err = client.Mail(fromAddr); err != nil {
		return fmt.Errorf("failed to set sender: %w", err)
	}
	if err = client.Rcpt(toAddr); err != nil {
		return fmt.Errorf("failed to set recipient: %w", err)
	}

	// Send the email data
	wc, err := client.Data()
	if err != nil {
		return fmt.Errorf("failed to get data writer: %w", err)
	}
	defer wc.Close()

	_, err = wc.Write([]byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to write email body: %w", err)
	}

	return nil
}

